    </svg></div></div><div class="code-content"><div class="code-block dsa_article_code_active" data-lang="cpp"><div class="line-numbers line-num"><span>1</span><span>2</span><span>3</span><span>4</span><span>5</span><span>6</span><span>7</span><span>8</span><span>9</span><span>10</span><span>11</span><span>12</span><span>13</span><span>14</span><span>15</span><span>16</span><span>17</span><span>18</span><span>19</span><span>20</span><span>21</span><span>22</span><span>23</span><span>24</span><span>25</span><span>26</span><span>27</span><span>28</span><span>29</span><span>30</span><span>31</span><span>32</span><span>33</span><span>34</span><span>35</span><span>36</span><span>37</span><span>38</span><span>39</span><span>40</span><span>41</span><span>42</span><span>43</span><span>44</span><span>45</span><span>46</span><span>47</span></div><pre class="wp-block-code"><code lang="cpp" class="language-cpp">#include &lt;bits/stdc++.h&gt;
using namespace std;

// Class to solve 0/1 Knapsack using memoization
class Solution {
public:
    // Function to compute maximum value
    int knapSackUtil(int ind, int W, vector&lt;int&gt;&amp; wt, 
                     vector&lt;int&gt;&amp; val, vector&lt;vector&lt;int&gt;&gt;&amp; dp) {
        // Base case: if only one item left
        if (ind == 0) {
            if (wt[0] &lt;= W) return val[0];
            else return 0;
        }
        // If already computed return it
        if (dp[ind][W] != -1) return dp[ind][W];

        // Exclude current item
        int notTaken = knapSackUtil(ind - 1, W, wt, val, dp);

        // Include current item if possible
        int taken = INT_MIN;
        if (wt[ind] &lt;= W) 
            taken = val[ind] + knapSackUtil(ind - 1, W - wt[ind], 
                                            wt, val, dp);

        // Store result in dp
        return dp[ind][W] = max(notTaken, taken);
    }

    // Main function to call
    int knapSack(int W, vector&lt;int&gt;&amp; wt, vector&lt;int&gt;&amp; val, int n) {
        vector&lt;vector&lt;int&gt;&gt; dp(n, vector&lt;int&gt;(W + 1, -1));
        return knapSackUtil(n - 1, W, wt, val, dp);
    }
};

// Driver code
int main() {
    int n = 4, W = 7;
    vector&lt;int&gt; wt = {1, 3, 4, 5};
    vector&lt;int&gt; val = {1, 4, 5, 7};
    Solution obj;
    cout &lt;&lt; obj.knapSack(W, wt, val, n) &lt;&lt; endl;
    return 0;
}
</code></pre></div><div class="code-block" data-lang="java"><div class="line-numbers line-num"><span>1</span><span>2</span><span>3</span><span>4</span><span>5</span><span>6</span><span>7</span><span>8</span><span>9</span><span>10</span><span>11</span><span>12</span><span>13</span><span>14</span><span>15</span><span>16</span><span>17</span><span>18</span><span>19</span><span>20</span><span>21</span><span>22</span><span>23</span><span>24</span><span>25</span><span>26</span><span>27</span><span>28</span><span>29</span><span>30</span><span>31</span><span>32</span><span>33</span><span>34</span><span>35</span><span>36</span><span>37</span><span>38</span><span>39</span><span>40</span><span>41</span><span>42</span><span>43</span><span>44</span><span>45</span></div><pre class="wp-block-code"><code lang="java" class="language-java">import java.util.*;

// Class to solve 0/1 Knapsack using memoization
class Solution {
    // Function to compute maximum value
    int knapSackUtil(int ind, int W, int[] wt, int[] val, int[][] dp) {
        // Base case: if only one item left
        if (ind == 0) {
            if (wt[0] &lt;= W) return val[0];
            else return 0;
        }
        // If already computed return it
        if (dp[ind][W] != -1) return dp[ind][W];

        // Exclude current item
        int notTaken = knapSackUtil(ind - 1, W, wt, val, dp);

        // Include current item if possible
        int taken = Integer.MIN_VALUE;
        if (wt[ind] &lt;= W) 
            taken = val[ind] + knapSackUtil(ind - 1, W - wt[ind], wt, val, dp);

        // Store result in dp
        return dp[ind][W] = Math.max(notTaken, taken);
    }

    // Main function to call
    int knapSack(int W, int[] wt, int[] val, int n) {
        int[][] dp = new int[n][W + 1];
        for (int[] row : dp) Arrays.fill(row, -1);
        return knapSackUtil(n - 1, W, wt, val, dp);
    }
}

// Driver class
public class Main {
    public static void main(String[] args) {
        int n = 4, W = 7;
        int[] wt = {1, 3, 4, 5};
        int[] val = {1, 4, 5, 7};
        Solution obj = new Solution();
        System.out.println(obj.knapSack(W, wt, val, n));
    }
}
</code></pre></div><div class="code-block" data-lang="python"><div class="line-numbers line-num"><span>1</span><span>2</span><span>3</span><span>4</span><span>5</span><span>6</span><span>7</span><span>8</span><span>9</span><span>10</span><span>11</span><span>12</span><span>13</span><span>14</span><span>15</span><span>16</span><span>17</span><span>18</span><span>19</span><span>20</span><span>21</span><span>22</span><span>23</span><span>24</span><span>25</span><span>26</span><span>27</span><span>28</span><span>29</span><span>30</span><span>31</span><span>32</span><span>33</span><span>34</span><span>35</span><span>36</span><span>37</span><span>38</span><span>39</span></div><pre class="wp-block-code"><code lang="python" class="language-python"># Class to solve 0/1 Knapsack using memoization
class Solution:
    # Function to compute maximum value
    def knapSackUtil(self, ind, W, wt, val, dp):
        # Base case: if only one item left
        if ind == 0:
            if wt[0] &lt;= W:
                return val[0]
            else:
                return 0
        # If already computed return it
        if dp[ind][W] != -1:
            return dp[ind][W]

        # Exclude current item
        notTaken = self.knapSackUtil(ind - 1, W, wt, val, dp)

        # Include current item if possible
        taken = float('-inf')
        if wt[ind] &lt;= W:
            taken = val[ind] + self.knapSackUtil(ind - 1, W - wt[ind], wt, val, dp)

        # Store result in dp
        dp[ind][W] = max(notTaken, taken)
        return dp[ind][W]

    # Main function to call
    def knapSack(self, W, wt, val, n):
        dp = [[-1 for _ in range(W + 1)] for _ in range(n)]
        return self.knapSackUtil(n - 1, W, wt, val, dp)

# Driver code
