</code></pre></div><div class="code-block" data-lang="javascript"><div class="line-numbers line-num"><span>1</span><span>2</span><span>3</span><span>4</span><span>5</span><span>6</span><span>7</span><span>8</span><span>9</span><span>10</span><span>11</span><span>12</span><span>13</span><span>14</span><span>15</span><span>16</span><span>17</span><span>18</span><span>19</span><span>20</span><span>21</span><span>22</span><span>23</span><span>24</span><span>25</span><span>26</span><span>27</span><span>28</span><span>29</span><span>30</span><span>31</span><span>32</span><span>33</span><span>34</span><span>35</span><span>36</span><span>37</span><span>38</span><span>39</span><span>40</span><span>41</span><span>42</span><span>43</span></div><pre class="wp-block-code"><code lang="javascript" class="language-javascript">// Class to solve 0/1 Knapsack using memoization
class Solution {
    // Function to compute maximum value
    knapSackUtil(ind, W, wt, val, dp) {
        // Base case: if only one item left
        if (ind === 0) {
            if (wt[0] &lt;= W) return val[0];
            else return 0;
        }
        // If already computed return it
        if (dp[ind][W] !== -1) return dp[ind][W];

        // Exclude current item
        let notTaken = this.knapSackUtil(ind - 1, W, wt, val, dp);

        // Include current item if possible
        let taken = -Infinity;
        if (wt[ind] &lt;= W) {
            taken = val[ind] + this.knapSackUtil(ind - 1, 
                                                 W - wt[ind], 
                                                 wt, val, dp);
        }

        // Store result in dp
        dp[ind][W] = Math.max(notTaken, taken);
        return dp[ind][W];
    }

    // Main function to call
    knapSack(W, wt, val, n) {
        let dp = Array.from({ length: n }, 
                            () =&gt; Array(W + 1).fill(-1));
        return this.knapSackUtil(n - 1, W, wt, val, dp);
    }
}

